import{_ as i,o as t,c as a,ai as l}from"./chunks/framework.BSOyxTN6.js";const m=JSON.parse('{"title":"Rust中的迭代器Iter","description":"","frontmatter":{},"headers":[],"relativePath":"basic-docs/Iter/readme.md","filePath":"basic-docs/Iter/readme.md"}'),o={name:"basic-docs/Iter/readme.md"};function r(c,e,d,n,s,p){return t(),a("div",null,[...e[0]||(e[0]=[l('<h1 id="rust中的迭代器iter" tabindex="-1">Rust中的迭代器Iter <a class="header-anchor" href="#rust中的迭代器iter" aria-label="Permalink to “Rust中的迭代器Iter”">​</a></h1><h2 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to “核心概念”">​</a></h2><p><strong>迭代器</strong>是rust中一种遍历集合（Vec、HashMap、数组等）或序列的工具，允许逐个访问集合中的元素，无需关心 集合的底层实现。</p><p><strong>核心特点</strong>：</p><ol><li>惰性求值：迭代器本身不会主动遍历元素，只有调用消费型方法（<code>next()</code>、<code>collect()</code>、<code>for_each()</code>等）才会执行遍历。</li><li>零成本抽象：rust编译器会将迭代器优化成与手写循环一样的性能，不会有额外开销。</li></ol><p>实现了<code>Iterator</code>特征才能称之为迭代器；实现了<code>IntoIterator</code>特征则可以通过<code>into_iter</code>，<code>iter</code>等方法变成一个迭代器。</p><h2 id="基本使用" tabindex="-1">基本使用 <a class="header-anchor" href="#基本使用" aria-label="Permalink to “基本使用”">​</a></h2><p>几乎所有集合类型都提供了获取迭代器的方法： <code>iter()</code>：获取不可变引用的迭代器（遍历 &amp;T）； <code>iter_mut()</code>：获取可变引用的迭代器（遍历 &amp;mut T）； <code>into_iter()</code>：获取消费集合的迭代器（遍历 T，集合本身会被消耗）；</p><h3 id="迭代器适配器" tabindex="-1">迭代器适配器 <a class="header-anchor" href="#迭代器适配器" aria-label="Permalink to “迭代器适配器”">​</a></h3><p>消费掉迭代器，然后返回一个新的迭代器</p><ol><li>map()：对每个元素执行映射操作，返回新元素组成的迭代器</li><li>flat_map()：将一个多层的迭代器打平为一层</li><li>filter()：过滤出满足条件的元素</li><li>filter_map()：【过滤】和【映射】双重作用</li><li>take(n)：取出前n个元素</li><li>take_while()：按条件取元素直到第一个不满足的条件的元素出现（短路），之后的元素都会被舍弃，传入值为闭包</li><li>skip(n)：跳过前n个元素</li><li>skip_while()：按条件跳过元素指导第一个满足条件的元素出现（短路），之后的元素都会被保留，传入值为闭包</li><li>chain()：拼接两个迭代器</li><li>enumerate()：获取元素的索引和值，返回的迭代器元素为<code>(索引,元素)</code>元组</li><li>zip()：将两个迭代器打包为元组迭代器（取最短的长度）</li><li>rev()：反转迭代器</li></ol><h3 id="消费者适配器" tabindex="-1">消费者适配器 <a class="header-anchor" href="#消费者适配器" aria-label="Permalink to “消费者适配器”">​</a></h3><p>只要迭代器上的方法内部调用了next()方法，那么这就是消费者适配器，消费者适配器也会消耗掉迭代器上的元素。</p><ol><li>collect()：将迭代器转为集合（如Vec、HashMap）</li><li>for_each()：对每个元素执行操作</li><li>fold()：自定义聚合(折叠)逻辑，比如拼接字符串，接受值为初始值和闭包，下面的<strong>sum</strong>和<strong>product</strong>方法都是基于这个实现</li><li>sum()：求和</li><li>product()：求乘积</li><li>count()：统计元素个数</li><li>all()：所有元素满足条件则返回true（短路，遇到第一个<strong>不满足</strong>则停止）</li><li>any()：任意元素满足条件则返回true（短路，遇到第一个<strong>满足</strong>则停止）</li><li>min()/max()：返回迭代器中的最小/最大值（<code>Option&lt;Item&gt;</code>）</li><li>find()：找到第一个满足条件的元素(<code>Option&lt;Item&gt;</code>)</li><li>contains()：检查是否包含指定值，返回bool值</li></ol>',14)])])}const _=i(o,[["render",r]]);export{m as __pageData,_ as default};
